def _load_table():
    raw = zlib.decompress(base64.b85decode(_DATA))
    tbl = {}
    for i in range(0, len(raw), 4):
        k, v = struct.unpack('>HH', raw[i:i+4])
        tbl[k] = v
    return tbl

TABLE = _load_table()

def decode_gbk(raw_bytes):
    """Pure Python GBK->Unicode decoder."""
    result = []
    i, n = 0, len(raw_bytes)
    while i < n:
        b = raw_bytes[i]
        if b < 0x80:
            result.append(chr(b))
            i += 1
        elif 0x81 <= b <= 0xFE and i + 1 < n:
            trail = raw_bytes[i + 1]
            if 0x40 <= trail <= 0xFE and trail != 0x7F:
                key = (b << 8) | trail
                result.append(chr(TABLE.get(key, b)))
                i += 2
                continue
            result.append(chr(b))
            i += 1
        else:
            result.append(chr(b))
            i += 1
    return ''.join(result)


def fix_zip_filename(name):
    """Recover GBK-encoded filename that was mis-decoded as cp437 by zipfile."""
    if all(ord(c) <= 127 for c in name):
        return name
    try:
        raw = name.encode('cp437')
    except (UnicodeEncodeError, LookupError):
        return name
    try:
        return raw.decode('gb18030')
    except (UnicodeDecodeError, LookupError):
        pass
    return decode_gbk(raw) or name
